diff --git a/src/apprt/gtk/class/surface.zig b/src/apprt/gtk/class/surface.zig
index 26009ef79ed..a2ff52aa9fb 100644
--- a/src/apprt/gtk/class/surface.zig
+++ b/src/apprt/gtk/class/surface.zig
@@ -2713,6 +2713,18 @@ pub const Surface = extern struct {
         };
     }

+    /// Public method to forward mouse down events from parent widgets
+    /// (e.g., ScrolledWindow capturing middle-clicks).
+    pub fn forwardMouseDown(
+        self: *Self,
+        gesture: *gtk.GestureClick,
+        n_press: c_int,
+        x: f64,
+        y: f64,
+    ) void {
+        gcMouseDown(gesture, n_press, x, y, self);
+    }
+
     fn gcMouseDown(
         gesture: *gtk.GestureClick,
         _: c_int,
diff --git a/src/apprt/gtk/class/surface_scrolled_window.zig b/src/apprt/gtk/class/surface_scrolled_window.zig
index 488fdb3f4e6..a1d849f7453 100644
--- a/src/apprt/gtk/class/surface_scrolled_window.zig
+++ b/src/apprt/gtk/class/surface_scrolled_window.zig
@@ -138,6 +138,24 @@ pub const SurfaceScrolledWindow = extern struct {
         };
     }

+    /// Handle middle-click at the ScrolledWindow level to prevent the
+    /// ScrolledWindow from intercepting it. This forwards the event to
+    /// the Surface's mouse handler.
+    fn scrolledWindowMouseDown(
+        gesture: *gtk.GestureClick,
+        n_press: c_int,
+        x: f64,
+        y: f64,
+        self: *Self,
+    ) callconv(.c) void {
+        const surface = self.private().surface orelse return;
+        surface.forwardMouseDown(gesture, n_press, x, y);
+
+        // Claim the gesture to prevent the Surface's GestureClick from
+        // also handling this event (which would cause double-paste).
+        _ = gesture.as(gtk.Gesture).setState(.claimed);
+    }
+
     fn propSurface(
         self: *Self,
         _: *gobject.ParamSpec,
@@ -189,6 +207,7 @@ pub const SurfaceScrolledWindow = extern struct {
             // Bindings
             class.bindTemplateCallback("scrollbar_policy", &closureScrollbarPolicy);
             class.bindTemplateCallback("notify_surface", &propSurface);
+            class.bindTemplateCallback("scrolled_window_mouse_down", &scrolledWindowMouseDown);

             // Properties
             gobject.ext.registerProperties(class, &.{
diff --git a/src/apprt/gtk/ui/1.5/surface-scrolled-window.blp b/src/apprt/gtk/ui/1.5/surface-scrolled-window.blp
index 722c4427b3f..9855fdd0b12 100644
--- a/src/apprt/gtk/ui/1.5/surface-scrolled-window.blp
+++ b/src/apprt/gtk/ui/1.5/surface-scrolled-window.blp
@@ -7,5 +7,12 @@ template $GhostttySurfaceScrolledWindow: Adw.Bin {
   Gtk.ScrolledWindow {
     hscrollbar-policy: never;
     vscrollbar-policy: bind $scrollbar_policy(template.config) as <Gtk.PolicyType>;
+    kinetic-scrolling: false;
+
+    GestureClick {
+      pressed => $scrolled_window_mouse_down();
+      button: 2;
+      propagation-phase: capture;
+    }
   }
 }
